#!/bin/bash
set -e
cd /workspaces/Purgatoire
python3 - << 'PYEOF'
import base64, os
os.makedirs("pages", exist_ok=True)
os.makedirs("worker/src", exist_ok=True)
with open("pages/personnalite.md","wb") as f: f.write(base64.b64decode(""))
with open("worker/src/index.js","wb") as f: f.write(base64.b64decode(""))
print("✅ 2 fichiers écrits")
PYEOF
echo "🔧 Déploiement worker..."
cd worker && npx wrangler deploy && cd ..
git add pages/personnalite.md worker/src/index.js
git commit -m "feat: profil axes dans modal carte membre"
git push
echo "🚀 Déployé !"
